## Block 2 — JS function

**Find:** the `// ============== Atom canvas animation ==============` section in the `<script>` near the bottom. It contains `function buildAtomCanvas()` and the IntersectionObserver that calls it.

**Replace the entire function + observer with:**

```javascript
// ============== 3D Atomization Visualization (Three.js) ==============
async function init3DAtomViz() {
  const container = document.getElementById('atom-canvas');
  if (!container) return;

  try {
    const test = document.createElement('canvas');
    const gl = test.getContext('webgl2') || test.getContext('webgl');
    if (!gl) throw new Error('No WebGL');
  } catch (e) {
    container.innerHTML = '<div style="display:flex;align-items:center;justify-content:center;height:100%;color:var(--text-3);font-family:Geist Mono;font-size:11px;letter-spacing:0.05em;">3D visualization unavailable</div>';
    return;
  }

  const reducedMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
  const isMobile = window.innerWidth < 640;

  const loader = document.createElement('div');
  loader.style.cssText = 'position:absolute;inset:0;display:flex;align-items:center;justify-content:center;color:var(--text-3);font-family:Geist Mono;font-size:11px;letter-spacing:0.05em;opacity:0.5;transition:opacity 0.4s ease;';
  loader.textContent = 'Initializing 3D scene...';
  container.appendChild(loader);

  try {
    const THREE = await import('https://unpkg.com/three@0.158.0/build/three.module.js');
    const W = container.offsetWidth, H = container.offsetHeight;

    const scene = new THREE.Scene();
    const camera = new THREE.PerspectiveCamera(38, W / H, 0.1, 100);
    camera.position.set(0, 1.4, 8);
    camera.lookAt(0, 0, 0);

    const renderer = new THREE.WebGLRenderer({ antialias: !isMobile, alpha: true, powerPreference: 'high-performance' });
    renderer.setSize(W, H);
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, isMobile ? 1.5 : 2));
    renderer.outputColorSpace = THREE.SRGBColorSpace;
    renderer.toneMapping = THREE.ACESFilmicToneMapping;
    renderer.toneMappingExposure = 1.05;
    container.appendChild(renderer.domElement);
    renderer.domElement.style.cssText = 'width:100%;height:100%;display:block;';

    scene.add(new THREE.AmbientLight(0xffffff, 0.55));
    const key = new THREE.DirectionalLight(0xfff7e8, 1.1); key.position.set(3, 5, 4); scene.add(key);
    const fill = new THREE.DirectionalLight(0xB85C38, 0.35); fill.position.set(-4, -2, 2); scene.add(fill);
    const rim = new THREE.DirectionalLight(0x9ea6c4, 0.5); rim.position.set(0, 2, -5); scene.add(rim);

    const COLORS = { indigo: new THREE.Color(0x1E1B4B), terracotta: new THREE.Color(0xB85C38), dark: new THREE.Color(0x1a1a1a) };

    const sourcePositions = [
      new THREE.Vector3(-4.6, 1.6, -0.3),
      new THREE.Vector3(-4.6, 0.0, 0.3),
      new THREE.Vector3(-4.6, -1.6, -0.3)
    ];
    const sourceNodes = sourcePositions.map((pos) => {
      const mesh = new THREE.Mesh(
        new THREE.SphereGeometry(0.16, 32, 32),
        new THREE.MeshPhysicalMaterial({ color: COLORS.dark, roughness: 0.55, metalness: 0.15, clearcoat: 0.6, clearcoatRoughness: 0.3 })
      );
      mesh.position.copy(pos);
      scene.add(mesh);
      const halo = new THREE.Mesh(
        new THREE.RingGeometry(0.22, 0.28, 48),
        new THREE.MeshBasicMaterial({ color: COLORS.dark, transparent: true, opacity: 0.10, side: THREE.DoubleSide })
      );
      halo.position.copy(pos); halo.lookAt(camera.position); scene.add(halo);
      return { mesh, halo, basePos: pos.clone() };
    });

    const sinkPositions = [
      new THREE.Vector3(4.6, 2.0, 0.3),
      new THREE.Vector3(4.6, 0.7, -0.3),
      new THREE.Vector3(4.6, -0.7, 0.3),
      new THREE.Vector3(4.6, -2.0, -0.3)
    ];
    const sinkNodes = sinkPositions.map((pos, i) => {
      const mesh = new THREE.Mesh(
        new THREE.SphereGeometry(0.18, 32, 32),
        new THREE.MeshPhysicalMaterial({ color: COLORS.indigo, emissive: COLORS.indigo, emissiveIntensity: 0.45, roughness: 0.25, metalness: 0.5, clearcoat: 0.7, clearcoatRoughness: 0.2 })
      );
      mesh.position.copy(pos); scene.add(mesh);
      const halo = new THREE.Mesh(
        new THREE.RingGeometry(0.24, 0.36, 48),
        new THREE.MeshBasicMaterial({ color: COLORS.indigo, transparent: true, opacity: 0.18, side: THREE.DoubleSide })
      );
      halo.position.copy(pos); halo.lookAt(camera.position); scene.add(halo);
      const halo2 = new THREE.Mesh(
        new THREE.RingGeometry(0.4, 0.46, 48),
        new THREE.MeshBasicMaterial({ color: COLORS.indigo, transparent: true, opacity: 0.06, side: THREE.DoubleSide })
      );
      halo2.position.copy(pos); halo2.lookAt(camera.position); scene.add(halo2);
      return { mesh, halo, halo2, basePos: pos.clone(), phaseOffset: i * 0.7 };
    });

    sourceNodes.forEach((s) => {
      sinkNodes.forEach((t) => {
        const mid = new THREE.Vector3(0, (s.basePos.y + t.basePos.y) / 2, (s.basePos.z + t.basePos.z) / 2);
        const curve = new THREE.QuadraticBezierCurve3(s.basePos, mid, t.basePos);
        const geo = new THREE.BufferGeometry().setFromPoints(curve.getPoints(40));
        scene.add(new THREE.Line(geo, new THREE.LineBasicMaterial({ color: COLORS.indigo, transparent: true, opacity: 0.035 })));
      });
    });

    const atomGeoLarge = new THREE.IcosahedronGeometry(0.13, 0);
    const atomGeoSmall = new THREE.IcosahedronGeometry(0.10, 0);
    const atoms = [];
    const maxAtoms = isMobile ? 12 : 22;

    function spawnAtom() {
      if (atoms.length >= maxAtoms) return;
      const source = sourceNodes[Math.floor(Math.random() * sourceNodes.length)];
      const sink = sinkNodes[Math.floor(Math.random() * sinkNodes.length)];
      const isAccent = Math.random() < 0.18;
      const isSmall = Math.random() < 0.3;
      const color = isAccent ? COLORS.terracotta : COLORS.indigo;
      const mat = new THREE.MeshPhysicalMaterial({ color, emissive: color, emissiveIntensity: isAccent ? 0.55 : 0.4, roughness: 0.22, metalness: 0.45, clearcoat: 0.8, clearcoatRoughness: 0.15 });
      const mesh = new THREE.Mesh(isSmall ? atomGeoSmall : atomGeoLarge, mat);
      mesh.position.copy(source.basePos); scene.add(mesh);
      const mid = new THREE.Vector3(
        (source.basePos.x + sink.basePos.x) / 2 + (Math.random() - 0.5) * 0.6,
        (source.basePos.y + sink.basePos.y) / 2 + (Math.random() - 0.5) * 2.2,
        (Math.random() - 0.5) * 2.8
      );
      atoms.push({
        mesh, mat,
        curve: new THREE.QuadraticBezierCurve3(source.basePos.clone(), mid, sink.basePos.clone()),
        phase: 0, speed: 0.13 + Math.random() * 0.08,
        rotSpeed: new THREE.Vector3((Math.random() - 0.5) * 1.8, (Math.random() - 0.5) * 1.8, (Math.random() - 0.5) * 0.8)
      });
    }

    if (!reducedMotion) {
      for (let i = 0; i < 6; i++) setTimeout(spawnAtom, i * 240);
    } else {
      for (let i = 0; i < 4; i++) { spawnAtom(); if (atoms[i]) atoms[i].phase = 0.5; }
    }
    const spawnInterval = !reducedMotion ? setInterval(spawnAtom, 340) : null;

    setTimeout(() => { loader.style.opacity = '0'; setTimeout(() => loader.remove(), 500); }, 200);

    const clock = new THREE.Clock();
    let isVisible = true;

    function animate() {
      requestAnimationFrame(animate);
      if (!isVisible) return;
      const dt = Math.min(clock.getDelta(), 0.05);
      const t = clock.elapsedTime;

      for (let i = atoms.length - 1; i >= 0; i--) {
        const a = atoms[i];
        if (!reducedMotion) a.phase += a.speed * dt;
        if (a.phase >= 1) { scene.remove(a.mesh); a.mat.dispose(); atoms.splice(i, 1); continue; }
        const pos = a.curve.getPoint(a.phase);
        a.mesh.position.copy(pos);
        a.mesh.scale.setScalar(0.35 + Math.sin(a.phase * Math.PI) * 0.75);
        if (!reducedMotion) {
          a.mesh.rotation.x += a.rotSpeed.x * dt;
          a.mesh.rotation.y += a.rotSpeed.y * dt;
          a.mesh.rotation.z += a.rotSpeed.z * dt;
        }
        a.mat.emissiveIntensity = 0.3 + Math.sin(a.phase * Math.PI) * 0.4;
      }

      sinkNodes.forEach((n) => {
        const pulse = 1 + Math.sin(t * 1.4 + n.phaseOffset) * 0.04;
        n.mesh.scale.setScalar(pulse);
        n.halo.material.opacity = 0.16 + Math.sin(t * 1.4 + n.phaseOffset) * 0.04;
      });

      if (!reducedMotion) {
        camera.position.x = Math.sin(t * 0.08) * 0.35;
        camera.position.y = 1.4 + Math.cos(t * 0.06) * 0.12;
        camera.lookAt(0, 0, 0);
      }

      renderer.render(scene, camera);
    }
    animate();

    document.addEventListener('visibilitychange', () => {
      isVisible = !document.hidden;
      if (isVisible) clock.getDelta();
    });

    new ResizeObserver(() => {
      const nw = container.offsetWidth, nh = container.offsetHeight;
      if (nw > 0 && nh > 0) { camera.aspect = nw / nh; camera.updateProjectionMatrix(); renderer.setSize(nw, nh); }
    }).observe(container);

  } catch (err) {
    console.error('3D scene init failed:', err);
    loader.textContent = 'Visualization unavailable';
  }
}

const atomObserver = new IntersectionObserver((entries) => {
  entries.forEach((e) => { if (e.isIntersecting) { init3DAtomViz(); atomObserver.disconnect(); } });
}, { threshold: 0.15 });

const atomCanvas = document.getElementById('atom-canvas');
if (atomCanvas) atomObserver.observe(atomCanvas);
```

---

## Design notes

* **3 source nodes** (dark matte spheres, faint halos) on left, slightly z-offset for depth
* **4 sink nodes** (indigo glowing spheres, double halos) on right, subtle pulse breathing
* **Faceted icosahedron atoms** on bezier curves through 3D space (z-varying paths = real depth, not flat)
* **Lighting:** warm key from top-front, terracotta fill from below, cool rim from behind, ACES filmic tone mapping
* **Camera drift** — slow sin/cos orbit for subtle cinematic life
* **Mobile-optimized:** DPR cap 1.5, no antialias, max 12 atoms (vs 22 desktop)
* **Lazy-loaded** Three.js via dynamic import — first paint unaffected
* **Respects** `prefers-reduced-motion` — static mid-path composition for reduced-motion users
* **Tab-visibility pause** for battery
* **WebGL fallback** — clean message if browser can't run it

---

